function solve(nums: number[]): number {
    const n = nums.length;
    let maxVal = 0;

    // Try all possible ways to assign elements to A, B, C
    for (let mask = 0; mask < (1 << n); mask++) {
        const A: number[] = [];
        const B: number[] = [];
        const C: number[] = [];

        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                A.push(nums[i]);
            } else {
                B.push(nums[i]);
            }
        }

        // Calculate XOR(A), AND(B), XOR(C)
        let xorA = 0;
        for (const num of A) {
            xorA ^= num;
        }

        let andB = 0;
        for (const num of B) {
            if (andB === 0) {
                andB = num;
